Here's a complete example of data-driven MSTest tests for your `PriceCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: inline test cases for CalculateTotal ---
    [TestMethod]
    [DataRow(1, 10.00, 10.00)]
    [DataRow(5, 3.50, 17.50)]
    [DataRow(0, 99.99, 0.00)]
    [DataRow(100, 0.01, 1.00)]
    public void CalculateTotal_ReturnsExpected(int quantity, double unitPrice, double expected)
    {
        var result = _calculator.CalculateTotal(quantity, (decimal)unitPrice);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DataRow: inline test cases for ApplyDiscount ---
    [TestMethod]
    [DataRow(100.00, 0.10, 90.00)]
    [DataRow(200.00, 0.25, 150.00)]
    [DataRow(50.00, 0.00, 50.00)]
    [DataRow(50.00, 1.00, 0.00)]
    public void ApplyDiscount_ReturnsExpected(double total, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)total, (decimal)discount);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData: complex/reusable test cases from a property ---
    [TestMethod]
    [DynamicData(nameof(CalculateTotalCases), DynamicDataSourceType.Property)]
    public void CalculateTotal_DynamicCases(int quantity, decimal unitPrice, decimal expected)
    {
        var result = _calculator.CalculateTotal(quantity, unitPrice);
        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<object[]> CalculateTotalCases => new[]
    {
        new object[] { 2, 15.99m, 31.98m },
        new object[] { 10, 5.00m, 50.00m },
        new object[] { 1, 0.01m, 0.01m },
    };

    // --- DynamicData: from a method (useful for generated/conditional data) ---
    [TestMethod]
    [DynamicData(nameof(GetDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_DynamicCases(decimal total, decimal discount, decimal expected)
    {
        var result = _calculator.ApplyDiscount(total, discount);
        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<object[]> GetDiscountCases()
    {
        yield return new object[] { 500m, 0.15m, 425m };
        yield return new object[] { 1000m, 0.50m, 500m };
        yield return new object[] { 0m, 0.10m, 0m };
    }

    // --- Edge case: invalid inputs throw ---
    [TestMethod]
    [DataRow(-1, 10.00)]
    [DataRow(1, -5.00)]
    public void CalculateTotal_InvalidInputs_Throws(int quantity, double unitPrice)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(quantity, (decimal)unitPrice));
    }

    [TestMethod]
    [DataRow(100.00, -0.01)]
    [DataRow(100.00, 1.01)]
    public void ApplyDiscount_InvalidDiscount_Throws(double total, double discount)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)total, (decimal)discount));
    }
}
```

**Key points:**

- **`[DataRow]`** — best for simple inline literals (note: `decimal` isn't allowed, use `double` and cast)
- **`[DynamicData]`** — use a `Property` or `Method` returning `IEnumerable<object[]>` for complex types, computed data, or reusable datasets
- **`[TestInitialize]`** — sets up a fresh instance per test
- Edge cases (zero, boundary, invalid) are included to ensure robustness

Adapt the method signatures and exception types to match your actual `PriceCalculator` implementation.
